namespace sv_482b62543cee4d5783a849b22d3ae3f2.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

namespace sv_482b62543cee4d5783a849b22d3ae3f2.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Italian pizza with fresh mozzarella, basil, and tomato sauce.", 30),
            new(2, "Pasta Carbonara", "Creamy Roman pasta with pancetta, egg yolk, and pecorino cheese.", 25),
            new(3, "Tiramisu", "Layered dessert with espresso-soaked ladyfingers and mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken pieces in a rich, spiced tomato-cream sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach curry with cubes of soft paneer cheese.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Sushi Rolls", "Vinegared rice and fresh fish wrapped in nori seaweed.", 40),
            new(8, "Ramen", "Rich pork bone broth with wheat noodles, chashu, and soft-boiled egg.", 120),
            new(9, "Tempura", "Lightly battered and deep-fried shrimp and seasonal vegetables.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_482b62543cee4d5783a849b22d3ae3f2.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <ul>
        @foreach (var recipe in DisplayRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <br /><small>Prep time: @recipe.PrepTimeMinutes min</small>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;
    private CancellationTokenSource _disposeCts = new();

    private IEnumerable<Recipe> DisplayRecipes =>
        string.Equals(Sort, "newest", StringComparison.OrdinalIgnoreCase)
            ? _recipes!.OrderByDescending(r => r.Id)
            : string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
                ? _recipes!.OrderBy(r => r.PrepTimeMinutes)
                : _recipes!;

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        var cts = _loadCts;
        var cuisineId = CuisineId;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(cuisineId, cts.Token);

            if (cts.Token.IsCancellationRequested)
                return;

            _recipes = results;
            _loadedCuisineId = cuisineId;
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Expected when navigating away or switching cuisines — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", cuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", cuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _loadCts?.Dispose();
    }
}

